#include "ComparisonProcessor.h"
namespace referencelab {
void ComparisonProcessor::prepare(double sr,int max){rate=sr;juce::dsp::ProcessSpec spec{sr,(juce::uint32)max,1};for(auto* c:{&mixChain,&referenceChain})for(int ch=0;ch<2;++ch){c->hp[ch].prepare(spec);c->bell[ch].prepare(spec);c->lp[ch].prepare(spec);}update(settings);}
void ComparisonProcessor::update(const ComparisonSettings&s){if(initialised&&s.bypass==settings.bypass&&s.highPassHz==settings.highPassHz&&s.bellHz==settings.bellHz&&s.bellGainDb==settings.bellGainDb&&s.bellQ==settings.bellQ&&s.lowPassHz==settings.lowPassHz&&s.mode==settings.mode)return;settings=s;initialised=true;auto hp=juce::dsp::IIR::Coefficients<float>::makeHighPass(rate,juce::jlimit(10.f,(float)rate*.45f,s.highPassHz));auto bell=juce::dsp::IIR::Coefficients<float>::makePeakFilter(rate,juce::jlimit(10.f,(float)rate*.45f,s.bellHz),juce::jmax(.1f,s.bellQ),juce::Decibels::decibelsToGain(s.bellGainDb));auto lp=juce::dsp::IIR::Coefficients<float>::makeLowPass(rate,juce::jlimit(20.f,(float)rate*.49f,s.lowPassHz));for(auto* c:{&mixChain,&referenceChain})for(int ch=0;ch<2;++ch){c->hp[ch].coefficients=hp;c->bell[ch].coefficients=bell;c->lp[ch].coefficients=lp;}}
void ComparisonProcessor::applyListeningMode(juce::AudioBuffer<float>&b,ListeningMode m)noexcept{if(b.getNumChannels()<2||m==ListeningMode::stereo)return;for(int i=0;i<b.getNumSamples();++i){auto l=b.getSample(0,i),r=b.getSample(1,i);auto mid=.5f*(l+r),side=.5f*(l-r);if(m==ListeningMode::side){b.setSample(0,i,side);b.setSample(1,i,-side);}else{b.setSample(0,i,mid);b.setSample(1,i,mid);}}}
void ComparisonProcessor::processChain(juce::AudioBuffer<float>&b,Chain&c)noexcept{for(int ch=0;ch<juce::jmin(2,b.getNumChannels());++ch){juce::dsp::AudioBlock<float> block(b);auto one=block.getSingleChannelBlock((size_t)ch);juce::dsp::ProcessContextReplacing<float> ctx(one);c.hp[ch].process(ctx);c.bell[ch].process(ctx);c.lp[ch].process(ctx);}}
void ComparisonProcessor::process(juce::AudioBuffer<float>&m,juce::AudioBuffer<float>&r)noexcept{applyListeningMode(m,settings.mode);applyListeningMode(r,settings.mode);if(!settings.bypass){processChain(m,mixChain);processChain(r,referenceChain);}}
}
